#### Implementation Notes

After matching, insert content with attribution mark:

```typescript
function insertWithAttribution(view: EditorView, text: string, match: CopyRecordMatch | null) {
  const { tr } = view.state;
  const from = view.state.selection.from;
  const node = view.state.schema.text(text);
  tr.replaceSelectionWith(node);
  const to = from + text.length;

  const attrs = match
    ? { color: 'red', confidence: match.confidence, paste_event_id: match.id,
        original_paste_content: text, created_at: Date.now(), scoring_mode: 'edit-distance' }
    : { color: 'green', confidence: 1.0, created_at: Date.now(), scoring_mode: 'edit-distance' };

  tr.addMark(from, to, view.state.schema.marks.attribution.create(attrs));
  view.dispatch(tr);
}
```

