type AttributionColor = 'red' | 'yellow' | 'green';

export function computeTransition(normalizedDistance: number, currentColor: AttributionColor): AttributionColor {
  // normalizedDistance = fraction of characters changed (0 = identical, 1 = completely different)
  if (normalizedDistance >= 0.7) return 'green';
  if (normalizedDistance >= 0.2) return 'yellow';
