#### Implementation Notes

Use ProseMirror decorations (not marks) for visual rendering. This keeps the overlay purely visual without modifying the document:

```typescript
const attributionDecoPlugin = new Plugin({
  state: {
    init: () => ({ active: false }),
    apply(tr, value) {
      const meta = tr.getMeta(attributionDecoPluginKey);
      if (meta !== undefined) return { active: meta };
      return value;
    },
  },
  props: {
    decorations(state) {
      const { active } = this.getState(state);
      if (!active) return DecorationSet.empty;
      const decos: Decoration[] = [];
      state.doc.descendants((node, pos) => {
        node.marks.forEach(mark => {
          if (mark.type.name === 'attribution') {
            decos.push(Decoration.inline(pos, pos + node.nodeSize, {
              class: `attribution-${mark.attrs.color}`,
              style: getAttributionStyle(mark.attrs),
            }));
          }
        });
      });
      return DecorationSet.create(state.doc, decos);
    },
  },
});
```

