#### Implementation Notes

Map edit distance (0.2 to 0.7 range) to yellow opacity:

```typescript
function getYellowOpacity(editDistance: number): number {
  // editDistance 0.2 → opacity 0.3 (darker), editDistance 0.7 → opacity 0.05 (lighter)
  const t = (editDistance - 0.2) / 0.5; // normalize to 0-1
  return 0.3 - (t * 0.25); // 0.3 to 0.05
}

function getAttributionStyle(attrs: Record<string, any>): string {
  if (attrs.color === 'yellow') {
    const opacity = getYellowOpacity(attrs.edit_distance_from_paste ?? 0.2);
    return `background: rgba(234, 179, 8, ${opacity})`;
  }
  return '';
}
```

